import { UnionFind } from './UnionFind';

/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, k) {
    // Sort edges by time in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find data structure
    const uf = new UnionFind(n);

    // Keep track of the number of connected components
    let components = n;

    // Iterate through edges in order of increasing time
    for (const [u, v, time] of edges) {
        // If the nodes are in different sets, merge them
        if (uf.find(u) !== uf.find(v)) {
            uf.union(u, v);
            components--;
        }

        // Check if we have at least k connected components
        if (components >= k) {
            return time;
        }
    }

    // If we haven't found the answer, return the time of the last edge
    return edges[edges.length - 1][2];
}

// Union-Find data structure implementation
class UnionFind {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        this.rank = Array(n).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) return false;

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
        return true;
    }
}

